{
var bgInput = inputs.Length > 0 ? inputs[0] : null;
var width = GetFloat(parameters, "width", 0.8f);
var height = GetFloat(parameters, "height", 0.6f);
var borderW = GetFloat(parameters, "borderWidth", 0.03f);
var cornerR = GetFloat(parameters, "cornerRadius", 0.08f);
var bgColor = GetColor(parameters, "bgColor", Color.FromRgb(45, 40, 55));
var borderColor = GetColor(parameters, "borderColor", Color.FromRgb(160, 140, 180));
var innerHL = GetColor(parameters, "innerHighlight", Color.FromRgb(70, 60, 85));
var titleBar = GetBool(parameters, "titleBar", true);
var offsetX = GetFloat(parameters, "offsetX", 0f);
var offsetY = GetFloat(parameters, "offsetY", 0f);

var tileSize = context.TileSize;
var buffer = bgInput != null ? bgInput.Clone() : new PixelBuffer(tileSize, tileSize);

var bgR = bgColor.R / 255f; var bgG = bgColor.G / 255f; var bgB = bgColor.B / 255f;
var bR = borderColor.R / 255f; var bG = borderColor.G / 255f; var bB = borderColor.B / 255f;
var hlR = innerHL.R / 255f; var hlG = innerHL.G / 255f; var hlB = innerHL.B / 255f;

var halfSize = tileSize * 0.5f;
var panelW = tileSize * width * 0.5f;
var panelH = tileSize * height * 0.5f;
var cornerPx = tileSize * cornerR;
var borderPx = tileSize * borderW;
var cx = halfSize + offsetX * tileSize;
var cy = halfSize + offsetY * tileSize;

var titleH = titleBar ? panelH * 0.18f : 0f;

buffer.ParallelForEachPixel((x, y) =>
{
    var px = MathF.Abs(x + 0.5f - cx);
    var py = MathF.Abs(y + 0.5f - cy);

    if (px > panelW || py > panelH) return;

    // Signed distance to rounded rectangle
    var rx = Math.Max(0f, px - (panelW - cornerPx));
    var ry = Math.Max(0f, py - (panelH - cornerPx));
    var cornerDist = MathF.Sqrt(rx * rx + ry * ry);

    var body = false;
    var border = false;
    var titleFill = false;

    if (cornerDist > cornerPx + borderPx || px > panelW || py > panelH)
        return;

    if (cornerDist > cornerPx)
    {
        // Border corner
        border = true;
    }
    else if (px > panelW - borderPx || py > panelH - borderPx)
    {
        // Border edge
        border = true;
    }
    else if (titleBar && py < titleH)
    {
        titleFill = true;
    }
    else
    {
        body = true;
    }

    if (border)
    {
        // Border with 3D bevel
        var bevel = 1f;
        if (px < panelW * 0.5f && py < panelH * 0.5f)
            bevel = 1.3f; // top-left highlight
        else if (px > panelW * 0.5f || py > panelH * 0.5f)
            bevel = 0.7f; // bottom-right shadow
        buffer.SetPixel(x, y,
            Math.Clamp(bR * bevel, 0f, 1f),
            Math.Clamp(bG * bevel, 0f, 1f),
            Math.Clamp(bB * bevel, 0f, 1f), 1f);
    }
    else if (titleFill)
    {
        // Title bar: slightly brighter background
        var t = 1f - py / titleH * 0.3f;
        buffer.SetPixel(x, y,
            Math.Clamp(hlR * t, 0f, 1f),
            Math.Clamp(hlG * t, 0f, 1f),
            Math.Clamp(hlB * t, 0f, 1f), 1f);
    }
    else if (body)
    {
        // Body: subtle gradient from center
        var dark = 1f - (py / panelH) * 0.15f;
        buffer.SetPixel(x, y,
            Math.Clamp(bgR * dark, 0f, 1f),
            Math.Clamp(bgG * dark, 0f, 1f),
            Math.Clamp(bgB * dark, 0f, 1f), 1f);
    }
});

return buffer;
}
